```python
def separate_paren_groups(paren_string: str) -> List[str]:
    groups = []
    stack = []
    current_group = []

    for char in paren_string.replace(" ", ""):
        if char == '(':
            if not stack:
                current_group = []
            stack.append(char)
            current_group.append(char)
        elif char == ')':
            if stack:
                stack.pop()
                current_group.append(char)
                if not stack:
                    groups.append(''.join(current_group))

    return groups
```

```python
def separate_paren_groups(paren_string: str) -> List[str]:
    result = []
    current_group = []
    balance = 0

    for char in paren_string.replace(" ", ""):
        if char == '(':
            if balance == 0 and current_group:
                result.append(''.join(current_group))
                current_group = []
            current_group.append(char)
            balance += 1
        elif char == ')':
            current_group.append(char)
            balance -= 1

        if balance == 0 and current_group:
            result.append(''.join(current_group))
            current_group = []

    return result
```

```python
def separate_paren_groups(paren_string: str) -> List[str]:
    groups = []
    current_group = []
    depth = 0

    for char in paren_string.replace(" ", ""):
        if char == '(':
            if depth == 0 and current_group:
                groups.append(''.join(current_group))
                current_group = []
            current_group.append(char)
            depth += 1
        elif char == ')':
            current_group.append(char)
            depth -= 1
            if depth == 0:
                groups.append(''.join(current_group))
                current_group = []

    if current_group:
        groups.append(''.join(current_group))

    return groups
```

```python
def separate_paren_groups(paren_string: str) -> List[str]:
    paren_string = paren_string.replace(" ", "")
    groups = []
    count = 0
    start = 0

    for i, char in enumerate(paren_string):
        if char == '(':
            if count == 0:
                start = i
            count += 1
        elif char == ')':
            count -= 1
            if count == 0:
                groups.append(paren_string[start:i + 1])

    return groups
```

